sealed class Exception: kotlin.Exception() {
    
    class DuplicateNode(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    
    class NoSuchNode(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    
    class UnparseableCreds(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    
    class PhraseCorrupted(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    
    class Rpc(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    
    class Argument(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    
    class Other(
        
        val `code`: kotlin.Int, 
        
        val `msg`: kotlin.String, 
        
        val `values`: Map<kotlin.String, kotlin.String>
        ) : Exception() {
        override val message
            get() = "code=${ `code` }, msg=${ `msg` }, values=${ `values` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<Exception> {
        override fun lift(error_buf: RustBuffer.ByValue): Exception = FfiConverterTypeError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeError : FfiConverterRustBuffer<Exception> {
    override fun read(buf: ByteBuffer): Exception {
        

        return when(buf.getInt()) {
            1 -> Exception.DuplicateNode(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            2 -> Exception.NoSuchNode(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            3 -> Exception.UnparseableCreds(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            4 -> Exception.PhraseCorrupted(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            5 -> Exception.Rpc(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            6 -> Exception.Argument(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            7 -> Exception.Other(
                FfiConverterInt.read(buf),
                FfiConverterString.read(buf),
                FfiConverterMapStringString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: Exception): ULong {
        return when(value) {
            is Exception.DuplicateNode -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterInt.allocationSize(value.`code`)
                + FfiConverterString.allocationSize(value.`msg`)
                + FfiConverterMapStringString.allocationSize(value.`values`)
            )
            is Exception.NoSuchNode -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterInt.allocationSize(value.`code`)
                + FfiConverterString.allocationSize(value.`msg`)
                + FfiConverterMapStringString.allocationSize(value.`values`)
            )
            is Exception.UnparseableCreds -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterInt.allocationSize(value.`code`)
                + FfiConverterString.allocationSize(value.`msg`)
                + FfiConverterMapStringString.allocationSize(value.`values`)
            )
            is Exception.PhraseCorrupted -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
